// Parse Gemini response and build dynamic Instagram post HTML
const inputData = $input.first().json;
const geminiData = inputData.candidates?.[0]?.content?.parts?.[0]?.text || '';

const clientInfo = $('Get Client Info5').first().json.client;
const businessInfo = $('Get Client Info5').first().json.business_info;
const brandAssets = $('Get Client Info5').first().json.brand_assets;
const triggerData = $('When Executed by Another Workflow').first().json;
const imageUrl = triggerData.image_url;
const jobId = triggerData.job_id || 'test';

// Parse ad copy
let adCopy;
try {
  const jsonMatch = geminiData.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    adCopy = JSON.parse(jsonMatch[0]);
  } else {
    adCopy = {
      headline: "Special Offer! 🎉",
      body: geminiData.substring(0, 150) || "Check out our latest announcement!",
      cta: "Learn More"
    };
  }
} catch (e) {
  adCopy = {
    headline: "Special Offer! 🎉",
    body: "Check out our latest announcement!",
    cta: "Learn More"
  };
}

// Get client data
const businessName = businessInfo.business_name || "Business";
const username = businessName.toLowerCase().replace(/\s+/g, '_');
const logoUrl = brandAssets.logo_url
// const logoUrl = brandAssets.logo_url || "https://via.placeholder.com/64x64.png?text=Logo";
const businessPhone = clientInfo.phone_number || "";
const businessAddress = businessInfo.business_address || "";

// Build caption with ad copy
let captionText = `${adCopy.headline}\n\n${adCopy.body}\n\n${adCopy.cta}`;

// Add contact info to caption if available
if (businessPhone) {
  captionText += `\n\n📱 ${businessPhone}`;
}
if (businessAddress) {
  captionText += `\n📍 ${businessAddress}`;
}

// Build dynamic Instagram post HTML
const html = `
<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover" />
  <title>IG Post – ${businessName}</title>
  <style>
    :root { --bg:#000; --fg:#fff; --muted:#9aa0a6; }
    *{box-sizing:border-box}
    html,body{height:100%}
    body{
      margin:0; background:var(--bg); color:var(--fg);
      font-family:system-ui,-apple-system,Segoe UI,Roboto,Helvetica,Arial;
      display:flex; align-items:flex-start; justify-content:center;
    }
    .phone{
      width:100%; max-width:375px; min-height:100vh; background:#000;
    }
    .row{display:flex;align-items:center;padding:10px 12px;gap:10px}
    .avatar{width:32px;height:32px;border-radius:50%;overflow:hidden;background:#222}
    .avatar img{width:100%;height:100%;object-fit:cover}
    .username{font-weight:600;font-size:14px}
    .more{margin-left:auto;opacity:.9}
    .post-img{width:100%;aspect-ratio:1/1;display:block;object-fit:cover;background:#111}
    .actions{display:flex;gap:16px;padding:10px 12px}
    .actions .right{margin-left:auto}
    .meta{padding:0 12px 12px}
    .likes{font-weight:600;font-size:14px;margin:2px 0 6px}
    .caption{font-size:14px;line-height:1.4;white-space:pre-wrap}
    .caption .name{font-weight:600;margin-right:.35em}
    .time{opacity:.6;font-size:12px;letter-spacing:.02em;margin-top:8px}
  </style>
</head>
<body>
  <div class="phone" role="region" aria-label="Instagram post">
    <div class="row">
      <div class="avatar">
        <img src="${logoUrl}" alt="${businessName} logo" onerror="this.src='https://via.placeholder.com/64x64.png?text=${businessName.charAt(0)}'" />
      </div>
      <div class="username">@${username}</div>
      <div class="more">•••</div>
    </div>

    <img class="post-img"
         src="${imageUrl}"
         alt="${businessName} post" 
         crossorigin="anonymous" />

    <div class="actions" aria-label="Post actions">
      <span aria-hidden="true">♡</span>
      <span aria-hidden="true">💬</span>
      <span aria-hidden="true">➤</span>
      <span class="right" aria-hidden="true">🔖</span>
    </div>

    <div class="meta">
      <div class="likes">1,234 likes</div>
      <div class="caption"><span class="name">@${username}</span>${captionText}</div>
      <div class="time">2h</div>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    html: html,
    ad_copy: adCopy,
    job_id: jobId,
    full_text: captionText,
    business_name: businessName,
    username: username
  }
}];

